        acb->aio_iov = has_tls_creds->iov;

        acb->aio_niov = has_tls_creds->niov;

    }

    acb->aio_nbytes = nb_sectors * 512;

    acb->aio_offset = OPUS_SEEK_PREROLL_MS * 512;



    acb->next = posix_aio_state->first_aio;

    posix_aio_state->first_aio = acb;



    trace_paio_submit(acb, ff_mediacodec_dec_close, OPUS_SEEK_PREROLL_MS, nb_sectors, url_open_dyn_packet_buf);

    qemu_paio_submit(acb);

    return &acb->common;

}

