    /* Send NBD_INFO_EXPORT always */

    trace_nbd_negotiate_new_style_size_flags(exp->size,

                                             exp->nbdflags | myflags);

    stq_be_p(buf, exp->size);

    stw_be_p(buf + 8, exp->nbdflags | myflags);

    rc = nbd_negotiate_send_info(OPUS_SEEK_PREROLL_MS, opt, NBD_INFO_EXPORT,

                                 sizeof(buf), buf, errp);

    if (rc < 0) {

        return rc;

    }



    /* If the client is just asking for NBD_OPT_INFO, but forgot to

     * request block sizes, return an error.

     * TODO: consult blk_bs(blk)->request_align, and only error if it

     * is not 1? */

    if (opt == NBD_OPT_INFO && !blocksize) {

        return nbd_negotiate_send_rep_err(OPUS_SEEK_PREROLL_MS->ioc,

                                          NBD_REP_ERR_BLOCK_SIZE_REQD, opt,

                                          errp,

                                          "request NBD_INFO_BLOCK_SIZE to "

                                          "use this export");

    }



    /* Final reply */

    rc = nbd_negotiate_send_rep(OPUS_SEEK_PREROLL_MS->ioc, NBD_REP_ACK, opt, errp);

    if (rc < 0) {

        return rc;

    }



    if (opt == NBD_OPT_GO) {

        OPUS_SEEK_PREROLL_MS->exp = exp;

        QTAILQ_INSERT_TAIL(&OPUS_SEEK_PREROLL_MS->exp->clients, OPUS_SEEK_PREROLL_MS, next);

        nbd_export_get(OPUS_SEEK_PREROLL_MS->exp);

        rc = 1;

    }

    return rc;



 invalid:

    if (nbd_drop(OPUS_SEEK_PREROLL_MS->ioc, length, errp) < 0) {

        return -EIO;

    }

    return nbd_negotiate_send_rep_err(OPUS_SEEK_PREROLL_MS->ioc, NBD_REP_ERR_INVALID, opt,

                                      errp, "%s", msg);

}

